fields.collector:
$key = 'HKLM:\SOFTWARE\Microsoft\PolicyManager\Current\Device\DeliveryOptimization'
$item = Get-ItemProperty -Path $key -ErrorAction SilentlyContinue
$o = [ordered]@{}
if ($item) {
    foreach ($p in $item.PSObject.Properties) {
        if ($p.Name -like 'PS*') { continue }
        $o[$p.Name] = "$($p.Value)"
    }
}
[pscustomobject]$o

$cfg = Get-DOConfig -ErrorAction Stop | Select-Object -Property *
$o = [ordered]@{}
foreach ($p in $cfg.PSObject.Properties) {
    if ($p.Name -like 'PS*' -or $p.Name -like 'Cim*') { continue }
    $o[$p.Name] = "$($p.Value)"
}
[pscustomobject]$o

